    storyConsequence: { correct: { zh: '驻军兵力——数据分析到位！做得漂亮！', en: 'Garrison Strength — Well done!' }, wrong: { zh: '数字有点不对——没关系，再仔细看看数据？', en: 'Not quite... Try again!' } }
